const items = $input.all();
const out = [];
const splitName = (full) => {
  const clean = String(full || '').split(',')[0].trim();
  const parts = clean.split(/\s+/).filter(Boolean);
  return { first: parts[0] || '', last: parts[parts.length - 1] || '' };
};
for (const it of items) {
  const r = it.json || {};
  const n = splitName(r.contact_name);
  const text =
    'PROJECT: ' + (r.project_name || 'unknown') + ' (' + (r.region || '?') + ', ' + (r.state || '?') + '), stage=' + (r.timeline_stage || 'unknown') + '. Owner: ' + (r.owner_company || 'unknown') + '.\n' +
    'COMPANY: ' + (r.company_name || '?') + ' — ' + (r.industry || 'unknown industry') + ', HQ ' + (r.hq_location || 'unknown') + ', ' + (r.company_size || 'unknown size') + '. Website: ' + (r.domain || 'unknown') + '. LinkedIn: ' + (r.company_linkedin || 'unknown') + '.\n' +
    'CONTACT: ' + (r.contact_name || '?') + ' — ' + (r.contact_title || '?') + ' (persona: ' + (r.persona || 'unclassified') + '). LinkedIn: ' + (r.contact_linkedin || 'unknown') + '.';
  out.push({ json: {
    lead_id: r.lead_id,
    domain: r.domain || '',
    contact_first_name: n.first,
    contact_last_name: n.last,
    input_text: text
  } });
}
return out;

const inputs = $('Build Research Input').all();
const research = $('Research Lead').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const base = (inputs[i] && inputs[i].json) ? inputs[i].json : {};
  const r = (research[i] && research[i].json) ? research[i].json : {};
  const h = items[i].json || {};
  const dossier = (r.output && typeof r.output === 'object') ? r.output : (typeof r === 'object' ? r : {});
  const hd = (h.data && typeof h.data === 'object') ? h.data : {};
  const email = hd.email || null;
  const confidence = (hd.score != null && Number.isFinite(Number(hd.score))) ? (Number(hd.score) / 100) : null;
  out.push({ json: {
    lead_id: base.lead_id,
    research_dossier: dossier,
    email: email,
    email_confidence: confidence
  } });
}
return out;
